mapper.select:
SELECT t1.id, t1.create_by, t1.login_time, t1.operate_time, t1.content, t1.action_code, t1.module_code, t1.target_type, t1.target_id, t1.target_name, t1.province_id, t1.prison_id, t1.prison_level, t1.path, t1.request_method, t1.params FROM t_oper_log t1 LEFT JOIN sys_user t2 ON t1.create_by = t2.username
COALESCE(t1.is_deleted, 0) = 0
AND ( t1.content LIKE concat('%', #{queryParams.keywords}, '%') OR t1.create_by LIKE concat('%', #{queryParams.keywords}, '%') OR t2.nickname LIKE concat('%', #{queryParams.keywords}, '%') OR t1.action_code LIKE concat('%', #{queryParams.keywords}, '%') OR t1.module_code LIKE concat('%', #{queryParams.keywords}, '%') OR t1.target_name LIKE concat('%', #{queryParams.keywords}, '%') OR t1.params LIKE concat('%', #{queryParams.keywords}, '%') )
AND t1.province_id = #{queryParams.provinceId}
AND t1.prison_level = #{queryParams.prisonLevel}
AND t1.operate_time >= #{startDate}
AND t1.operate_time <= #{endDate}
ORDER BY COALESCE(t1.operate_time, t1.create_time) DESC, t1.id DESC
